'use client';

import Link from 'next/link';
import { useSiteSettings } from '@/hooks/useSiteSettings';
import { ThemeLogo } from './ThemeLogo';

interface LogoProps {
  href?: string;
  className?: string;
  size?: 'sm' | 'md' | 'lg';
}

export function Logo({ href = '/', className = '', size = 'md' }: LogoProps) {
  const { settings, isLoading } = useSiteSettings();

  const sizeClasses = {
    sm: 'max-h-6',
    md: 'max-h-10',
    lg: 'max-h-16'
  };

  const sizeMultiplier = {
    sm: 0.6,
    md: 1,
    lg: 1.6
  };

  if (isLoading) {
    return (
      <div className={`animate-pulse bg-gray-200 dark:bg-gray-700 rounded ${sizeClasses[size]} w-24 ${className}`} />
    );
  }

  const logoWidth = Math.round(settings.logo.width * sizeMultiplier[size]);
  const logoHeight = Math.round(settings.logo.height * sizeMultiplier[size]);

  return (
    <Link 
      href={href} 
      className={`flex-shrink-0 ${className}`}
      aria-label={settings.logo.alt}
    >
      {(settings.logo.lightUrl || settings.logo.darkUrl) ? (
        <ThemeLogo
          lightUrl={settings.logo.lightUrl}
          darkUrl={settings.logo.darkUrl}
          alt={settings.logo.alt}
          width={logoWidth}
          height={logoHeight}
          className={sizeClasses[size]}
        />
      ) : (
        <div className={`text-xl font-bold text-primary-600 dark:text-primary-400 ${
          size === 'sm' ? 'text-lg' : size === 'lg' ? 'text-2xl' : 'text-xl'
        }`}>
          {settings.logo.alt}
        </div>
      )}
    </Link>
  );
}